mapper.select:
SELECT DISTINCT p.id, p.seller_id, p.title, p.description, p.category, p.`condition`,
       p.original_price, p.price, p.trade_location, p.negotiable, p.images,
       p.status, p.created_at, p.updated_at
FROM products p
LEFT JOIN users u ON p.seller_id = u.id
WHERE p.status = 'active'

    AND (MATCH(p.title, p.description) AGAINST(#{query.keyword} IN BOOLEAN MODE)
         OR u.nickname LIKE CONCAT('%', #{query.keyword}, '%'))


    AND p.category = #{query.category}


    AND p.`condition` = #{query.condition}


    AND p.price >= #{query.priceMin}


    AND p.price <= #{query.priceMax}


    ORDER BY p.price ASC
    ORDER BY p.price DESC
    ORDER BY p.created_at DESC

LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT p.id)
FROM products p
LEFT JOIN users u ON p.seller_id = u.id
WHERE p.status = 'active'

    AND (MATCH(p.title, p.description) AGAINST(#{query.keyword} IN BOOLEAN MODE)
         OR u.nickname LIKE CONCAT('%', #{query.keyword}, '%'))


    AND p.category = #{query.category}


    AND p.`condition` = #{query.condition}


    AND p.price >= #{query.priceMin}


    AND p.price <= #{query.priceMax}
